// أحجام الواصفات
std::array<VkDescriptorPoolSize, 2> poolSizes = {};

// Uniform Buffers
poolSizes[0].type = VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER;
poolSizes[0].descriptorCount = static_cast<uint32_t>(MAX_FRAMES_IN_FLIGHT);

// Combined Image Samplers
poolSizes[1].type = VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER;
poolSizes[1].descriptorCount = static_cast<uint32_t>(MAX_FRAMES_IN_FLIGHT);

VkDescriptorPoolCreateInfo poolInfo = {};
poolInfo.sType = VK_STRUCTURE_TYPE_DESCRIPTOR_POOL_CREATE_INFO;
poolInfo.poolSizeCount = static_cast<uint32_t>(poolSizes.size());
poolInfo.pPoolSizes = poolSizes.data();
poolInfo.maxSets = static_cast<uint32_t>(MAX_FRAMES_IN_FLIGHT);  // أقصى عدد Sets
poolInfo.flags = 0;  // بدون أعلام خاصة

VkDescriptorPool descriptorPool;
VkResult result = vkCreateDescriptorPool(
    device, &poolInfo, nullptr, &descriptorPool
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء Descriptor Pool!");
}

// واصف الـ Uniform Buffer
VkDescriptorSetLayoutBinding uboLayoutBinding = {};
uboLayoutBinding.binding = 0;  // رقم الربط في Shader
uboLayoutBinding.descriptorType = VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER;
uboLayoutBinding.descriptorCount = 1;  // عدد الواصفات
uboLayoutBinding.stageFlags = VK_SHADER_STAGE_VERTEX_BIT;  // مرحلة Vertex
uboLayoutBinding.pImmutableSamplers = nullptr;  // بدون Samplers

// واصف الـ Sampler
VkDescriptorSetLayoutBinding samplerLayoutBinding = {};
samplerLayoutBinding.binding = 1;
samplerLayoutBinding.descriptorType = VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER;
samplerLayoutBinding.descriptorCount = 1;
samplerLayoutBinding.stageFlags = VK_SHADER_STAGE_FRAGMENT_BIT;

// تجميع الربطات
std::array<VkDescriptorSetLayoutBinding, 2> bindings = {
    uboLayoutBinding, samplerLayoutBinding
};

VkDescriptorSetLayoutCreateInfo layoutInfo = {};
layoutInfo.sType = VK_STRUCTURE_TYPE_DESCRIPTOR_SET_LAYOUT_CREATE_INFO;
layoutInfo.bindingCount = static_cast<uint32_t>(bindings.size());
layoutInfo.pBindings = bindings.data();

VkDescriptorSetLayout descriptorSetLayout;
VkResult result = vkCreateDescriptorSetLayout(
    device, &layoutInfo, nullptr, &descriptorSetLayout
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء Descriptor Set Layout!");
}

